// Some portions generated by Codex
package org.eclipse.rdf4j.sail.lmdb.evaluation;

import static org.assertj.core.api.Assertions.assertThat;

import java.util.concurrent.atomic.AtomicLong;

import org.junit.jupiter.api.Test;

class RuntimeBuildAdmissionTest {

	@Test
	void completeProbeFloorAllowsOneTransactionalBuild() {
		RuntimeBuildAdmission admission = new RuntimeBuildAdmission(2L, () -> 0L);

		admission.recordProbeBatch(1L, 1L, 3L, 1L);
		assertThat(admission.tryStartBuild()).isFalse();
		admission.recordProbeBatch(1L, 1L, 5L, 2L);

		assertThat(admission.tryStartBuild()).isTrue();
		assertThat(admission.state()).isEqualTo(RuntimeBuildAdmission.State.BUILDING);
		assertThat(admission.recordBuildBatch(1L, 8L, 4L)).isTrue();
		assertThat(admission.commit()).isTrue();
		assertThat(admission.state()).isEqualTo(RuntimeBuildAdmission.State.COMMITTED);
		assertThat(admission.tryStartBuild()).isFalse();
		assertThat(admission.distinctProbes()).isEqualTo(2L);
		assertThat(admission.probeSeeks()).isEqualTo(2L);
		assertThat(admission.probeRows()).isEqualTo(8L);
		assertThat(admission.probeMatches()).isEqualTo(3L);
		assertThat(admission.buildSeeks()).isEqualTo(1L);
		assertThat(admission.buildRows()).isEqualTo(8L);
		assertThat(admission.buildMatches()).isEqualTo(4L);
	}

	@Test
	void buildWorkBeyondTwicePaidProbeWorkRefusesWithoutRetry() {
		RuntimeBuildAdmission admission = new RuntimeBuildAdmission(1L, () -> 0L);
		admission.recordProbeBatch(1L, 1L, 0L, 0L);
		assertThat(admission.tryStartBuild()).isTrue();

		assertThat(admission.recordBuildBatch(1L, 8L, 0L)).isTrue();
		assertThat(admission.buildWorkUnits()).isEqualTo(16L);
		assertThat(admission.maximumBuildWorkUnits()).isEqualTo(16L);
		assertThat(admission.recordBuildBatch(0L, 1L, 0L)).isFalse();

		assertThat(admission.state()).isEqualTo(RuntimeBuildAdmission.State.REFUSED);
		assertThat(admission.refusalReason()).isEqualTo(RuntimeBuildAdmission.RefusalReason.WORK_LIMIT);
		assertThat(admission.tryStartBuild()).isFalse();
		assertThat(admission.commit()).isFalse();
	}

	@Test
	void injectedClockIsSampledOnlyAtProbeAndBuildBoundaries() {
		AtomicLong clock = new AtomicLong(10L);
		RuntimeBuildAdmission admission = new RuntimeBuildAdmission(2L, clock::get);

		admission.recordProbeBatch(1L, 1L, 0L, 0L);
		clock.set(25L);
		admission.recordProbeBatch(1L, 1L, 0L, 0L);
		clock.set(30L);
		assertThat(admission.tryStartBuild()).isTrue();
		clock.set(42L);
		assertThat(admission.recordBuildBatch(0L, 1L, 1L)).isTrue();
		clock.set(50L);
		assertThat(admission.commit()).isTrue();

		assertThat(admission.probeNanos()).isEqualTo(20L);
		assertThat(admission.buildNanos()).isEqualTo(20L);
	}

	@Test
	void workLimitRefusalDoesNotSampleTheSameBuildBoundaryTwice() {
		AtomicLong calls = new AtomicLong();
		RuntimeBuildAdmission admission = new RuntimeBuildAdmission(1L, () -> calls.incrementAndGet() * 10L);

		admission.recordProbeBatch(1L, 1L, 0L, 0L);
		assertThat(admission.tryStartBuild()).isTrue();
		assertThat(admission.recordBuildBatch(0L, 17L, 0L)).isFalse();

		assertThat(admission.state()).isEqualTo(RuntimeBuildAdmission.State.REFUSED);
		assertThat(admission.refusalReason()).isEqualTo(RuntimeBuildAdmission.RefusalReason.WORK_LIMIT);
		assertThat(calls).hasValue(3L);
	}

	@Test
	void explicitRefusalAfterARecordedBuildBoundaryDoesNotResampleTime() {
		AtomicLong calls = new AtomicLong();
		RuntimeBuildAdmission admission = new RuntimeBuildAdmission(1L, () -> calls.incrementAndGet() * 10L);

		admission.recordProbeBatch(1L, 1L, 0L, 0L);
		assertThat(admission.tryStartBuild()).isTrue();
		assertThat(admission.recordBuildBatch(0L, 1L, 0L)).isTrue();
		admission.refuseAfterBuildBoundary(RuntimeBuildAdmission.RefusalReason.BUDGET);

		assertThat(admission.state()).isEqualTo(RuntimeBuildAdmission.State.REFUSED);
		assertThat(admission.refusalReason()).isEqualTo(RuntimeBuildAdmission.RefusalReason.BUDGET);
		assertThat(calls).hasValue(3L);
	}

	@Test
	void budgetCancellationAndEarlyCloseAreTerminalRefusals() {
		assertTerminalRefusal(RuntimeBuildAdmission.RefusalReason.BUDGET);
		assertTerminalRefusal(RuntimeBuildAdmission.RefusalReason.CANCELLED);

		RuntimeBuildAdmission closed = buildingAdmission();
		closed.close();
		assertThat(closed.state()).isEqualTo(RuntimeBuildAdmission.State.REFUSED);
		assertThat(closed.refusalReason()).isEqualTo(RuntimeBuildAdmission.RefusalReason.CLOSED);
		assertThat(closed.tryStartBuild()).isFalse();
	}

	private static void assertTerminalRefusal(RuntimeBuildAdmission.RefusalReason reason) {
		RuntimeBuildAdmission admission = buildingAdmission();
		admission.refuse(reason);
		assertThat(admission.state()).isEqualTo(RuntimeBuildAdmission.State.REFUSED);
		assertThat(admission.refusalReason()).isEqualTo(reason);
		assertThat(admission.tryStartBuild()).isFalse();
		assertThat(admission.commit()).isFalse();
	}

	private static RuntimeBuildAdmission buildingAdmission() {
		RuntimeBuildAdmission admission = new RuntimeBuildAdmission(1L, () -> 0L);
		admission.recordProbeBatch(1L, 1L, 0L, 0L);
		assertThat(admission.tryStartBuild()).isTrue();
		return admission;
	}
}
